code_changes.content:
[
  {
    "file": "lib/base64.c",
    "line": 203,
    "severity": "critical",
    "description": "Integer overflow vulnerability in base64_encode. Removed overflow check for 32-bit systems that prevented allocation size calculation overflow. When insize > UINT_MAX/4, the expression (insize + 2) / 3 * 4 + 1 can wrap around to a small value, causing malloc to allocate insufficient memory followed by buffer overflow during memcpy.",
    "fix_patch": "--- a/lib/base64.c
+++ b/lib/base64.c
@@ -200,6 +200,11 @@ static CURLcode base64_encode(const char *table64,
   if(!insize)
     insize = strlen(inputbuff);

+#if SIZEOF_SIZE_T == 4
+  if(insize > UINT_MAX/4)
+    return CURLE_OUT_OF_MEMORY;
+#endif
+
   base64data = output = malloc((insize + 2) / 3 * 4 + 1);
   if(!output)
     return CURLE_OUT_OF_MEMORY;
"
  },
  {
    "file": "lib/cookie.c",
    "line": 154,
    "severity": "high",
    "description": "Off-by-one error in cookie_tailmatch. Removed -1 offset when checking for domain separator character, causing boundary check to read one position too far. This allows invalid cookie domain matching where hostnames without proper '.' separators are incorrectly accepted, potentially allowing cookie scope bypass per RFC 6265 violation.",
    "fix_patch": "--- a/lib/cookie.c
+++ b/lib/cookie.c
@@ -151,7 +151,7 @@ static bool cookie_tailmatch(const char *cookie_domain,
    */
   if(hostname_len == cookie_domain_len)
     return TRUE;
-  if('.' == *(hostname + hostname_len - cookie_domain_len))
+  if('.' == *(hostname + hostname_len - cookie_domain_len - 1))
     return TRUE;
   return FALSE;
 }
"
  },
  {
    "file": "lib/transfer.c",
    "line": 166,
    "severity": "critical",
    "description": "Missing NULL pointer check in xfer_recv_shutdown. Removed validation of data and data->conn before dereferencing data->conn->sockfd on line 168. If either is NULL, this causes a NULL pointer dereference and crash. The NULL check is critical for defensive programming.",
    "fix_patch": "--- a/lib/transfer.c
+++ b/lib/transfer.c
@@ -163,6 +163,8 @@ static CURLcode xfer_recv_shutdown(struct Curl_easy *data, bool *done)
 {
   int sockindex;

+  if(!data || !data->conn)
+    return CURLE_FAILED_INIT;
   if(data->conn->sockfd == CURL_SOCKET_BAD)
     return CURLE_FAILED_INIT;
   sockindex = (data->conn->sockfd == data->conn->sock[SECONDARYSOCKET]);
"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 994,
    "severity": "high",
    "description": "Buffer overflow in passwd_callback. Removed check for buffer size (num parameter) before copying password. The function now unconditionally copies klen + 1 bytes into buf without verifying that num is large enough. An attacker providing a long password could overflow the buffer provided by OpenSSL.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -989,10 +989,12 @@ static int passwd_callback(char *buf, int num, int encrypting,
 {
   DEBUGASSERT(0 == encrypting);

-  if(!encrypting) {
+  if(!encrypting && num >= 0) {
     int klen = curlx_uztosi(strlen((char *)global_passwd));
-    memcpy(buf, global_passwd, klen + 1);
-    return klen;
+    if(num > klen) {
+      memcpy(buf, global_passwd, klen + 1);
+      return klen;
+    }
   }
   return 0;
 }
"
  },
  {
    "file": "lib/vtls/openssl.c",
    "line": 2364,
    "severity": "critical",
    "description": "Certificate verification bypass via embedded null bytes in Subject Alternative Names. Removed embedded null byte check (altlen == strlen(altptr)) that was explicitly documented as protection against embedded nulls in certificate SANs. An attacker can craft a certificate with an embedded null byte to bypass hostname verification, matching an arbitrary domain via null-termination truncation.",
    "fix_patch": "--- a/lib/vtls/openssl.c
+++ b/lib/vtls/openssl.c
@@ -2361,7 +2361,10 @@ static CURLcode ossl_verifyhost(struct Curl_easy *data,
              It has been however verified that in 0.9.6 and 0.9.7, IA5String
              is always null-terminated.
           */
-          if(subj_alt_hostcheck(data, altptr, altlen,
+          if((altlen == strlen(altptr)) &&
+             /* if this is not true, there was an embedded zero in the name
+                string and we cannot match it. */
+             subj_alt_hostcheck(data, altptr, altlen,
                                 peer->hostname, hostlen,
                                 peer->dispname)) {
             dnsmatched = TRUE;
"
  }
]

